export const nextGeneration = (liveCells: Set<string>): Set<string> => {
  const parse = (key: string): [number, number] => {
    const [x, y] = key.split(",").map(Number);
    return [x, y];
  };

  const countLiveNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCells.has(`${x + dx},${y + dy}`)) count++;
      }
    }
    return count;
  };

  const candidates = new Set<string>();
  for (const cell of liveCells) {
    const [x, y] = parse(cell);
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        candidates.add(`${x + dx},${y + dy}`);
      }
    }
  }

  const result = new Set<string>();
  for (const cell of candidates) {
    const [x, y] = parse(cell);
    const neighbors = countLiveNeighbors(x, y);
    const isAlive = liveCells.has(cell);
    if (isAlive && (neighbors === 2 || neighbors === 3)) {
      result.add(cell);
    } else if (!isAlive && neighbors === 3) {
      result.add(cell);
    }
  }
  return result;
};
